module RefModule(
    input clk,
    input reset,
    input start,
    input [3:0] n,
    output reg [31:0] result,
    output reg done
);
    reg [3:0] unused_current;
    reg [31:0] product;
    reg calculating;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            result <= 32'd1;
            done <= 1'b0;
            unused_current <= 4'd0;
            product <= 32'd1;
            calculating <= 1'b0;
        end else if (start && !calculating) begin
            unused_current <= n;
            product <= 32'd1;
            calculating <= 1'b1;
            done <= 1'b0;
        end else if (calculating) begin
            if (unused_current > 4'd1) begin
                product <= product * unused_current;
                unused_current <= unused_current - 1;
            end else begin
                result <= product;
                calculating <= 1'b0;
                done <= 1'b1;
            end
        end
    end
endmodule
